const input = $input.first().json.body || $input.first().json;

const name = (input.name || '').trim();
const email = (input.email || '').trim().toLowerCase();
const phone = (input.phone || '').trim();
const service = (input.service || '').trim();
const budget = (input.budget || '').trim();
const message = (input.message || '').trim();
const howHeard = (input['how-heard'] || input.how_heard || '').trim();
const leadMagnet = input.lead_magnet === true || input.lead_magnet === 'true';
const submittedAt = input.submitted_at || new Date().toISOString();
const sourcePage = (input.source_page || 'unknown').trim();
const sourceUrl = (input.source_url || '').trim();

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error('Invalid email address: ' + email);
}

const leadId = 'DA-' + Date.now().toString(36).toUpperCase();

return [{ json: {
  lead_id: leadId,
  name, email, phone, service, budget, message,
  how_heard: howHeard,
  lead_magnet: leadMagnet,
  submitted_at: submittedAt,
  source: leadMagnet ? 'lead_magnet' : 'contact_form',
  source_page: sourcePage,
  source_url: sourceUrl
}}];

const base = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts/main/brain';
const files = ['icp', 'pricing', 'company-brief', 'tone-of-voice', 'response-scaffolds', 'integrations'];

const brain = {};
for (const f of files) {
  brain[f] = await this.helpers.httpRequest({
    method: 'GET', url: `${base}/${f}.md`,
    returnFullResponse: false, encoding: 'text', json: false,
  });
}

const d = $input.first().json;
const isLeadMagnet = d.source === 'lead_magnet';

const pageContext = {
  home: 'They submitted from the home page: the pitch-level entry point. May not yet understand the 4-layer framework in depth. Keep reply intro-level.',
  automations: 'They submitted from the /automations page after reading the 4-layer deep-dive. Assume they understand Context + Skills + Automation + Agent and can reference those terms directly.',
  websites: 'They submitted from the /websites page, interested primarily in the Layer 4 interface surface (dashboards, client portals, front-ends). Frame the reply around that, not full-stack automation unless they ask.',
  unknown: 'Source page not specified.'
}[d.source_page] || 'Source page not specified.';

const leadMagnetRule = isLeadMagnet
  ? 'CRITICAL: source is lead_magnet. This person downloaded the 4-Layer Blueprint PDF, they did NOT send an enquiry. An empty message is EXPECTED and normal. Set icp_class=warm, priority=2, scaffold=G, summary="Downloaded the 4-Layer Blueprint", their_topic="the 4-Layer Blueprint", signals=["lead_magnet_download","self_educating","opted_in"], budget_fit=unknown. Never treat the empty message as confusing or low-confidence.'
  : 'source is a normal contact form enquiry. Use the standard A-F scaffold rules. If too short to classify, priority=2 scaffold=B. If spam, icp_class=not_fit.';

const qualifier_body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 600,
  system: 'You are the Digital Artifacts lead-qualifier (Layer 2 skill). Classify an inbound form submission against the ICP and pricing. Return strictly the JSON schema, no prose, no markdown fences. Never invent signals not in the message. ' + leadMagnetRule,
  messages: [{
    role: 'user',
    content: `<icp>\n${brain['icp']}\n</icp>\n\n<pricing>\n${brain['pricing']}\n</pricing>\n\n<source_page_context>\n${pageContext}\n</source_page_context>\n\n<submission>\nName: ${d.name}\nEmail: ${d.email}\nPhone: ${d.phone}\nService requested: ${d.service}\nBudget: ${d.budget}\nHow they heard: ${d.how_heard}\nSource: ${d.source}\nSource page: ${d.source_page}\nMessage:\n${d.message}\n</submission>\n\nReturn JSON: {"icp_class":"hot|warm|cool|not_fit","priority":1|2|3,"industry_archetype":"services|trades|sales|other","scaffold":"A|B|C|D|E|F|G","summary":"","their_topic":"","signals":[],"budget_fit":"above_floor|edge|below_floor|unknown","first_name":"","recommended_action":""}`
  }]
};

return [{ json: { ...d, brain: {
  icp: brain['icp'], pricing: brain['pricing'], company: brain['company-brief'],
  tone: brain['tone-of-voice'], scaffolds: brain['response-scaffolds'], integrations: brain['integrations']
}, qualifier_body, page_context: pageContext, is_lead_magnet: isLeadMagnet }}];

const prev = $('Fetch Brain (Layer 1)').item.json;
const claudeRes = $input.first().json;
const raw = claudeRes?.content?.[0]?.text || '';

let classification;
try {
  const jsonText = raw.trim().replace(/^```json\n?|```$/g, '');
  classification = JSON.parse(jsonText);
} catch (e) {
  classification = {
    icp_class: 'warm', priority: 2, industry_archetype: 'other',
    scaffold: prev.is_lead_magnet ? 'G' : 'B',
    summary: prev.is_lead_magnet ? 'Downloaded the 4-Layer Blueprint' : (prev.message || '').slice(0, 80),
    their_topic: prev.is_lead_magnet ? 'the 4-Layer Blueprint' : (prev.service || 'enquiry'),
    signals: prev.is_lead_magnet ? ['lead_magnet_download','self_educating','opted_in'] : [],
    budget_fit: 'unknown', first_name: (prev.name || '').split(' ')[0],
    recommended_action: 'manual review'
  };
}

const nowSyd = new Date(new Date().toLocaleString('en-US', { timeZone: 'Australia/Sydney' }));
const day = nowSyd.getDay();
const hour = nowSyd.getHours();
const inHours = day >= 1 && day <= 5 && hour >= 8 && hour < 20;
const mode = inHours ? 'in_hours' : 'out_of_hours';

const leadMagnetRule = prev.is_lead_magnet
  ? 'CRITICAL OVERRIDE: source is lead_magnet. Use Scaffold G only. They downloaded the 4-Layer Blueprint PDF, they did NOT send an enquiry. An empty message is EXPECTED. NEVER write "your message was empty" or "not sure what prompted you to reach out" or anything implying they sent an enquiry. Warm, low pressure, value first. Do NOT override to Scaffold D for out_of_hours, Scaffold G sends fine any time. Set scaffold_used=G, confidence=high.'
  : 'source is a normal contact form enquiry. Use the standard A-F scaffold rules exactly as before. If mode=out_of_hours, override scaffold with D. The reply MUST match the source_page_context.';

const draft_body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 900,
  system: 'You draft an email reply from Isaiah at Digital Artifacts to a new inbound lead (Layer 2 skill: inbound-reply-draft). HARD RULES: no em dashes ever, open with FirstName only (no \'Hi X\'), reference one specific detail, end with the booking link, sign off Isaiah only, max 4 short paragraphs. Use placeholder {{ BOOKING_LINK }} in the body. ' + leadMagnetRule + ' Return JSON only, no markdown fences.',
  messages: [{
    role: 'user',
    content: `<company>\n${prev.brain.company}\n</company>\n\n<pricing>\n${prev.brain.pricing}\n</pricing>\n\n<tone>\n${prev.brain.tone}\n</tone>\n\n<scaffolds>\n${prev.brain.scaffolds}\n</scaffolds>\n\n<source_page_context>\n${prev.page_context}\n</source_page_context>\n\n<classification>\n${JSON.stringify(classification)}\n</classification>\n\n<submission>\nName: ${prev.name}\nEmail: ${prev.email}\nService: ${prev.service}\nBudget: ${prev.budget}\nSource: ${prev.source}\nSource page: ${prev.source_page}\nMessage:\n${prev.message}\n</submission>\n\n<mode>${mode}</mode>\n\nReturn JSON: {"subject":"","body_plain":"","scaffold_used":"A|B|C|D|E|F|G","confidence":"high|medium|low","notes_for_isaiah":""}`
  }]
};

return [{ json: { ...prev, classification, mode, draft_body } }];

const prev = $('Parse Classification + Mode').item.json;
const raw = $input.first().json?.content?.[0]?.text || '';
let draft;
