  + '<tr>'
  + '<td valign="middle" style="vertical-align:middle;padding:0 26px 0 0;"><img src="https://digitalartifacts.com.au/brand/da-mark-tile.png" alt="Digital Artifacts" width="84" height="84" style="display:block;width:84px;height:84px;border:0;"></td>'
