  const esc = (text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const linked = esc.replace(/(https?:\/\/[^\s<]+)/g, '<a href="$1" style="color:#00C853;">$1</a>');
  const body = linked.replace(/\n/g, '<br>');
  return '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Helvetica,Arial,sans-serif;font-size:14px;line-height:1.6;color:#1B2838;">' + body + '</div>' + '<br><br>' + SIGNATURE_HTML;
}

draft.body_html = bodyToHtml(draft.body_plain);

