const msg = (d.message || '').slice(0, 300) + ((d.message || '').length > 300 ? '...' : '');
const firstName = c.first_name || (d.name || '').split(' ')[0];

const text = `🌙 AUTO-SENT (outside hours) · ${prio} ${prioWord} ${c.industry_archetype}

${firstName} · ${d.service || 'no service'} · ${c.budget_fit}
${(c.signals || []).slice(0,5).join(', ')}

ASK
${c.summary}

MESSAGE
${msg}

───────
SENT REPLY (Scaffold ${d.draft.scaffold_used}, ${d.draft.confidence} confidence)

${d.draft.subject}

${d.draft.body_plain}

───────
${d.draft.notes_for_isaiah || 'No flags.'} Follow up in the morning.`;

return [{ json: { ...d, telegram_text: text.slice(0, 3900) } }];

